import type { ContentPack, EnemyDef, Item, Rune, FloorDef, RuneLetter } from "../types";

/**
 * Runtime registries populated from loaded content packs.
 * Game logic queries these instead of raw JSON.
 */
class ContentRegistry {
  private enemies: Map<string, EnemyDef> = new Map();
  private items: Map<string, Item> = new Map();
  private runes: Map<RuneLetter, Rune> = new Map();
  private floors: Map<number, FloorDef> = new Map();
  private loadedPacks: string[] = [];

  /** Load a content pack into the registry */
  loadPack(pack: ContentPack): void {
    if (this.loadedPacks.includes(pack.id)) {
      console.warn(`Pack "${pack.id}" already loaded, skipping.`);
      return;
    }

    for (const enemy of pack.enemies) {
      this.enemies.set(enemy.id, enemy);
    }
    for (const item of pack.items) {
      this.items.set(item.id, item);
    }
    for (const rune of pack.runes) {
      this.runes.set(rune.letter, rune);
    }
    for (const floor of pack.floors) {
      this.floors.set(floor.id, floor);
    }

    this.loadedPacks.push(pack.id);
    console.log(`Loaded pack "${pack.name}" v${pack.version}: ${pack.enemies.length} enemies, ${pack.items.length} items, ${pack.runes.length} runes, ${pack.floors.length} floors`);
  }

  // ── Queries ──

  getEnemy(id: string): EnemyDef | undefined {
    return this.enemies.get(id);
  }

  getEnemiesForFloor(floorNum: number): EnemyDef[] {
    return Array.from(this.enemies.values()).filter(
      (e) => floorNum >= e.floorRange[0] && floorNum <= e.floorRange[1]
    );
  }

  getBossForFloor(floorNum: number): EnemyDef | undefined {
    return Array.from(this.enemies.values()).find(
      (e) => e.isBoss && floorNum >= e.floorRange[0] && floorNum <= e.floorRange[1]
    );
  }

  getItem(id: string): Item | undefined {
    return this.items.get(id);
  }

  getAllItems(): Item[] {
    return Array.from(this.items.values());
  }

  getRune(letter: RuneLetter): Rune | undefined {
    return this.runes.get(letter);
  }

  getAllRunes(): Rune[] {
    return Array.from(this.runes.values());
  }

  getFloor(num: number): FloorDef | undefined {
    return this.floors.get(num);
  }

  getAllFloors(): FloorDef[] {
    return Array.from(this.floors.values()).sort((a, b) => a.id - b.id);
  }

  /** Reset all registries */
  clear(): void {
    this.enemies.clear();
    this.items.clear();
    this.runes.clear();
    this.floors.clear();
    this.loadedPacks = [];
  }
}

/** Singleton content registry */
export const registry = new ContentRegistry();
