import type { KAPLAYCtx } from "kaplay";
import { getState, advanceTick, saveState } from "../state";
import { FloorGraph } from "../floor";
import type { GameState, RoomDef } from "../types";

/** Color palette for room types */
const ROOM_COLORS: Record<string, [number, number, number]> = {
  start: [60, 120, 60],
  combat: [150, 50, 50],
  forge: [180, 120, 40],
  shop: [50, 100, 150],
  rest: [60, 140, 100],
  boss: [180, 40, 180],
  exit: [200, 180, 60],
  empty: [80, 80, 80],
};

const FOG_COLOR: [number, number, number] = [30, 30, 40];
const CURRENT_RING_COLOR: [number, number, number] = [255, 255, 100];
const EDGE_COLOR: [number, number, number] = [50, 50, 60];
const EDGE_DISCOVERED_COLOR: [number, number, number] = [80, 80, 100];

const MAP_AREA = { x: 50, y: 70, w: 700, h: 450 };
const ROOM_RADIUS = 22;

export function registerFloorMap(k: KAPLAYCtx) {
  k.scene("floorMap", () => {
    let state: GameState;
    try {
      state = getState();
    } catch {
      k.add([
        k.text("No save data found.", { size: 24 }),
        k.pos(k.width() / 2, k.height() / 2),
        k.anchor("center"),
        k.color(200, 100, 100),
      ]);
      k.onMousePress(() => k.go("mainMenu"));
      return;
    }

    const floorDef = state.floors.find((f) => f.id === state.currentFloor);
    if (!floorDef) {
      k.add([
        k.text("Floor data missing!", { size: 24 }),
        k.pos(k.width() / 2, k.height() / 2),
        k.anchor("center"),
        k.color(200, 100, 100),
      ]);
      return;
    }

    const graph = new FloorGraph(floorDef);
    // Visit current room on entry
    graph.visitRoom(state.currentRoomId);

    const layout = graph.computeLayout();

    // ── Header ──
    k.add([
      k.text(`Floor ${floorDef.id} - ${floorDef.name}`, { size: 28 }),
      k.pos(k.width() / 2, 25),
      k.anchor("center"),
      k.color(200, 180, 100),
    ]);

    // ── Player Stats Bar ──
    k.add([
      k.text(
        `HP: ${state.player.stats.hp}/${state.player.stats.maxHp}  MP: ${state.player.stats.mana}/${state.player.stats.maxMana}  Lv: ${state.player.level}  Gold: ${state.player.gold}`,
        { size: 13 }
      ),
      k.pos(15, 55),
      k.color(150, 200, 150),
    ]);

    // Tick counter
    k.add([
      k.text(`Tick: ${state.dungeonTick}`, { size: 13 }),
      k.pos(k.width() - 15, 55),
      k.anchor("topright"),
      k.color(120, 120, 120),
    ]);

    // ── Draw Edges ──
    for (const room of graph.getAllRooms()) {
      const posA = layout.get(room.id);
      if (!posA) continue;
      const ax = MAP_AREA.x + posA.x * MAP_AREA.w;
      const ay = MAP_AREA.y + posA.y * MAP_AREA.h;

      for (const connId of room.connections) {
        // Avoid drawing each edge twice
        if (connId < room.id) continue;
        const posB = layout.get(connId);
        if (!posB) continue;
        const bx = MAP_AREA.x + posB.x * MAP_AREA.w;
        const by = MAP_AREA.y + posB.y * MAP_AREA.h;

        const connRoom = graph.getRoom(connId);
        const bothDiscovered = room.discovered && connRoom?.discovered;
        const col = bothDiscovered ? EDGE_DISCOVERED_COLOR : EDGE_COLOR;

        // Draw line as a thin rect rotated
        const dx = bx - ax;
        const dy = by - ay;
        const len = Math.sqrt(dx * dx + dy * dy);
        const angle = Math.atan2(dy, dx);

        k.add([
          k.rect(len, 2),
          k.pos(ax, ay),
          k.rotate(angle * (180 / Math.PI)),
          k.color(...col),
          k.opacity(bothDiscovered ? 0.8 : 0.3),
        ]);
      }
    }

    // ── Draw Room Nodes ──
    for (const room of graph.getAllRooms()) {
      const pos = layout.get(room.id);
      if (!pos) continue;
      const rx = MAP_AREA.x + pos.x * MAP_AREA.w;
      const ry = MAP_AREA.y + pos.y * MAP_AREA.h;

      if (!room.discovered) {
        // Fog node — small dim circle
        k.add([
          k.circle(ROOM_RADIUS * 0.6),
          k.pos(rx, ry),
          k.anchor("center"),
          k.color(...FOG_COLOR),
          k.opacity(0.5),
        ]);
        continue;
      }

      const isCurrent = room.id === state.currentRoomId;
      const isReachable = graph.canMoveTo(state.currentRoomId, room.id);
      const baseColor = ROOM_COLORS[room.type] || ROOM_COLORS.empty;

      // Current room ring
      if (isCurrent) {
        k.add([
          k.circle(ROOM_RADIUS + 5),
          k.pos(rx, ry),
          k.anchor("center"),
          k.color(...CURRENT_RING_COLOR),
          k.opacity(0.7),
        ]);
      }

      // Room circle
      const roomNode = k.add([
        k.circle(ROOM_RADIUS),
        k.pos(rx, ry),
        k.anchor("center"),
        k.color(...baseColor),
        k.opacity(room.visited ? 1.0 : 0.7),
        k.area({ shape: new k.Rect(k.vec2(-ROOM_RADIUS, -ROOM_RADIUS), ROOM_RADIUS * 2, ROOM_RADIUS * 2) }),
        "roomNode",
      ]);

      // Room type icon (single letter)
      const typeIcon: Record<string, string> = {
        start: "S",
        combat: "!",
        forge: "F",
        shop: "$",
        rest: "R",
        boss: "B",
        exit: "E",
        empty: ".",
      };
      k.add([
        k.text(typeIcon[room.type] || "?", { size: 16 }),
        k.pos(rx, ry),
        k.anchor("center"),
        k.color(240, 240, 240),
      ]);

      // Room name below
      k.add([
        k.text(room.name, { size: 10 }),
        k.pos(rx, ry + ROOM_RADIUS + 8),
        k.anchor("center"),
        k.color(160, 160, 170),
        k.opacity(0.8),
      ]);

      // Click handler for navigation
      if (isReachable && !isCurrent) {
        roomNode.onClick(() => {
          moveToRoom(room, graph);
        });
        roomNode.onHover(() => {
          k.setCursor("pointer");
        });
        roomNode.onHoverEnd(() => {
          k.setCursor("default");
        });
      }
    }

    // ── Room Info Panel ──
    const currentRoom = graph.getRoom(state.currentRoomId);
    if (currentRoom) {
      k.add([
        k.rect(780, 55, { radius: 6 }),
        k.pos(k.width() / 2, k.height() - 35),
        k.anchor("center"),
        k.color(20, 20, 30),
        k.opacity(0.9),
      ]);
      k.add([
        k.text(`${currentRoom.name}: ${currentRoom.description}`, { size: 14, width: 760 }),
        k.pos(k.width() / 2, k.height() - 35),
        k.anchor("center"),
        k.color(180, 180, 200),
      ]);
    }

    function moveToRoom(room: RoomDef, g: FloorGraph) {
      state.currentRoomId = room.id;
      g.visitRoom(room.id);

      const bossSpawns = advanceTick();

      // Save on each move
      saveState();

      // Check room type for scene transition
      if (room.type === "combat" || (bossSpawns && room.type !== "rest")) {
        // Go to combat scene
        k.go("combat");
      } else if (room.type === "boss") {
        k.go("combat");
      } else if (room.type === "forge") {
        k.go("forge");
      } else if (room.type === "exit") {
        // Floor cleared — advance to next floor
        if (state.currentFloor >= 12) {
          state.escaped = true;
          k.go("victory");
        } else {
          state.currentFloor++;
          const nextFloor = state.floors.find((f) => f.id === state.currentFloor);
          if (nextFloor) {
            state.currentRoomId = nextFloor.startRoomId;
          }
          saveState();
          k.go("floorMap");
        }
      } else if (room.type === "rest") {
        // Heal at rest room
        state.player.stats.hp = Math.min(
          state.player.stats.maxHp,
          state.player.stats.hp + Math.floor(state.player.stats.maxHp * 0.3)
        );
        state.player.stats.mana = Math.min(
          state.player.stats.maxMana,
          state.player.stats.mana + Math.floor(state.player.stats.maxMana * 0.5)
        );
        saveState();
        k.go("floorMap");
      } else {
        // Refresh floor map
        k.go("floorMap");
      }
    }
  });
}
