import type { ContentPack } from "../types";
import { registry } from "./registry";

/**
 * Fetch and load a content pack JSON from the public/packs/ directory.
 */
export async function loadContentPack(packPath: string): Promise<ContentPack> {
  const response = await fetch(packPath);
  if (!response.ok) {
    throw new Error(`Failed to load content pack: ${packPath} (${response.status})`);
  }
  const pack: ContentPack = await response.json();
  registry.loadPack(pack);
  return pack;
}

/**
 * Load the base game content pack.
 */
export async function loadBasePack(): Promise<ContentPack> {
  return loadContentPack("/packs/base-pack.json");
}
