import type { KAPLAYCtx } from "kaplay";
import { deleteSave } from "../state";

export function registerVictory(k: KAPLAYCtx) {
  k.scene("victory", () => {
    k.add([
      k.rect(k.width(), k.height()),
      k.pos(0, 0),
      k.color(10, 15, 10),
    ]);

    k.add([
      k.text("YOU ESCAPED!", { size: 48 }),
      k.pos(k.width() / 2, 180),
      k.anchor("center"),
      k.color(200, 220, 100),
    ]);

    k.add([
      k.text("Against all odds, you fought your way", { size: 18 }),
      k.pos(k.width() / 2, 260),
      k.anchor("center"),
      k.color(180, 180, 180),
    ]);

    k.add([
      k.text("through twelve floors of darkness.", { size: 18 }),
      k.pos(k.width() / 2, 290),
      k.anchor("center"),
      k.color(180, 180, 180),
    ]);

    k.add([
      k.text("Freedom awaits.", { size: 22 }),
      k.pos(k.width() / 2, 340),
      k.anchor("center"),
      k.color(200, 200, 120),
    ]);

    const btn = k.add([
      k.rect(220, 50, { radius: 8 }),
      k.pos(k.width() / 2, 440),
      k.anchor("center"),
      k.color(60, 100, 60),
      k.area(),
    ]);

    k.add([
      k.text("Main Menu", { size: 24 }),
      k.pos(k.width() / 2, 440),
      k.anchor("center"),
      k.color(220, 220, 220),
    ]);

    btn.onClick(() => {
      deleteSave();
      k.go("mainMenu");
    });
  });
}
