import type { KAPLAYCtx } from "kaplay";
import { deleteSave } from "../state";

export function registerGameOver(k: KAPLAYCtx) {
  k.scene("gameOver", () => {
    k.add([
      k.rect(k.width(), k.height()),
      k.pos(0, 0),
      k.color(15, 5, 5),
    ]);

    k.add([
      k.text("YOU HAVE PERISHED", { size: 42 }),
      k.pos(k.width() / 2, 200),
      k.anchor("center"),
      k.color(180, 40, 40),
    ]);

    k.add([
      k.text("The dungeon claims another soul.", { size: 18 }),
      k.pos(k.width() / 2, 270),
      k.anchor("center"),
      k.color(140, 100, 100),
    ]);

    const btn = k.add([
      k.rect(220, 50, { radius: 8 }),
      k.pos(k.width() / 2, 380),
      k.anchor("center"),
      k.color(80, 40, 40),
      k.area(),
    ]);

    k.add([
      k.text("Main Menu", { size: 24 }),
      k.pos(k.width() / 2, 380),
      k.anchor("center"),
      k.color(200, 200, 200),
    ]);

    btn.onClick(() => {
      deleteSave();
      k.go("mainMenu");
    });
  });
}
