import type { Rune, Spell, SpellAffinity, SpellEffect, RuneLetter } from "../types";
import { registry } from "../content";

/**
 * Determine the dominant affinity from a set of runes.
 * The affinity that appears most often wins; ties break alphabetically.
 */
function dominantAffinity(runes: Rune[]): SpellAffinity {
  const counts = new Map<SpellAffinity, number>();
  for (const r of runes) {
    counts.set(r.affinity, (counts.get(r.affinity) || 0) + 1);
  }

  let best: SpellAffinity = runes[0].affinity;
  let bestCount = 0;
  for (const [aff, count] of counts) {
    if (count > bestCount || (count === bestCount && aff < best)) {
      best = aff;
      bestCount = count;
    }
  }
  return best;
}

/**
 * Determine spell effect based on affinity.
 */
function effectForAffinity(affinity: SpellAffinity): SpellEffect {
  switch (affinity) {
    case "fire":
    case "lightning":
    case "shadow":
      return "damage";
    case "holy":
      return "heal";
    case "ice":
      return "debuff";
    case "earth":
      return "shield";
    case "arcane":
      return "buff";
    default:
      return "damage";
  }
}

/**
 * Calculate affinity bonus: if all runes share the same affinity,
 * power is multiplied by 1.5.
 */
function affinityBonus(runes: Rune[]): number {
  const allSame = runes.every((r) => r.affinity === runes[0].affinity);
  return allSame ? 1.5 : 1.0;
}

/**
 * Generate a spell name from the rune sequence.
 */
function generateSpellName(runes: Rune[], affinity: SpellAffinity, effect: SpellEffect): string {
  const prefixes: Record<SpellAffinity, string> = {
    fire: "Blaze",
    ice: "Frost",
    lightning: "Storm",
    earth: "Stone",
    shadow: "Dark",
    holy: "Divine",
    arcane: "Arcane",
  };

  const suffixes: Record<SpellEffect, string> = {
    damage: "Bolt",
    heal: "Grace",
    buff: "Ward",
    debuff: "Hex",
    shield: "Wall",
  };

  const prefix = prefixes[affinity] || "Mystic";
  const suffix = suffixes[effect] || "Spell";
  return `${prefix} ${suffix}`;
}

/**
 * Compose a spell from a sequence of rune letters.
 * Requires at least 2 runes. Returns null if any rune is unknown.
 */
export function composeSpell(runeLetters: RuneLetter[]): Spell | null {
  if (runeLetters.length < 2) return null;

  const runes: Rune[] = [];
  for (const letter of runeLetters) {
    const rune = registry.getRune(letter);
    if (!rune) return null;
    runes.push(rune);
  }

  const affinity = dominantAffinity(runes);
  const effect = effectForAffinity(affinity);
  const basePower = runes.reduce((sum, r) => sum + r.power, 0);
  const bonus = affinityBonus(runes);
  const power = Math.floor(basePower * bonus);
  const manaCost = Math.floor(power * 0.6);

  const name = generateSpellName(runes, affinity, effect);
  const id = `spell-${runeLetters.join("").toLowerCase()}-${Date.now()}`;

  return {
    id,
    name,
    runes: runeLetters,
    affinity,
    effect,
    power,
    manaCost,
    description: `${name}: ${effect} spell (${affinity}). Power ${power}, Cost ${manaCost} MP. Runes: ${runes.map((r) => r.name).join(" + ")}`,
  };
}

/**
 * Check if a player can learn a rune (from a rune stone item).
 */
export function learnRune(playerRunes: RuneLetter[], letter: RuneLetter): boolean {
  if (playerRunes.includes(letter)) return false;
  playerRunes.push(letter);
  return true;
}
