import type { FloorDef, RoomDef, RoomType } from "../types";

/**
 * Runtime helper that wraps a FloorDef and provides graph-traversal
 * and discovery logic for room navigation.
 */
export class FloorGraph {
  private roomMap: Map<string, RoomDef>;

  constructor(public readonly floor: FloorDef) {
    this.roomMap = new Map();
    for (const room of floor.rooms) {
      this.roomMap.set(room.id, room);
    }
  }

  /** Get a room by id */
  getRoom(id: string): RoomDef | undefined {
    return this.roomMap.get(id);
  }

  /** Get all rooms */
  getAllRooms(): RoomDef[] {
    return Array.from(this.roomMap.values());
  }

  /** Get the rooms connected to a given room */
  getConnections(roomId: string): RoomDef[] {
    const room = this.roomMap.get(roomId);
    if (!room) return [];
    return room.connections
      .map((id) => this.roomMap.get(id))
      .filter((r): r is RoomDef => r !== undefined);
  }

  /** Discover connected rooms (reveal them on the map) */
  discoverConnections(roomId: string): void {
    const connections = this.getConnections(roomId);
    for (const conn of connections) {
      conn.discovered = true;
    }
  }

  /** Mark a room as visited and discovered */
  visitRoom(roomId: string): RoomDef | undefined {
    const room = this.roomMap.get(roomId);
    if (!room) return undefined;
    room.visited = true;
    room.discovered = true;
    this.discoverConnections(roomId);
    return room;
  }

  /** Check if a move from current room to target room is valid */
  canMoveTo(fromId: string, toId: string): boolean {
    const from = this.roomMap.get(fromId);
    if (!from) return false;
    return from.connections.includes(toId);
  }

  /** Get start room */
  getStartRoom(): RoomDef | undefined {
    return this.roomMap.get(this.floor.startRoomId);
  }

  /** Get exit room */
  getExitRoom(): RoomDef | undefined {
    return this.roomMap.get(this.floor.exitRoomId);
  }

  /** Get all discovered rooms */
  getDiscoveredRooms(): RoomDef[] {
    return this.getAllRooms().filter((r) => r.discovered);
  }

  /** Get rooms by type */
  getRoomsByType(type: RoomType): RoomDef[] {
    return this.getAllRooms().filter((r) => r.type === type);
  }

  /**
   * Compute layout positions for rooms using a simple force-directed approach.
   * Returns a map of roomId -> { x, y } positions normalized to [0,1] range.
   */
  computeLayout(): Map<string, { x: number; y: number }> {
    const positions = new Map<string, { x: number; y: number }>();
    const rooms = this.getAllRooms();

    // Initial placement: circular layout
    rooms.forEach((room, i) => {
      const angle = (i / rooms.length) * Math.PI * 2;
      positions.set(room.id, {
        x: 0.5 + 0.35 * Math.cos(angle),
        y: 0.5 + 0.35 * Math.sin(angle),
      });
    });

    // Simple force-directed iterations
    for (let iter = 0; iter < 50; iter++) {
      for (const room of rooms) {
        const pos = positions.get(room.id)!;
        let fx = 0, fy = 0;

        // Repulsion from all other rooms
        for (const other of rooms) {
          if (other.id === room.id) continue;
          const opos = positions.get(other.id)!;
          const dx = pos.x - opos.x;
          const dy = pos.y - opos.y;
          const dist = Math.max(Math.sqrt(dx * dx + dy * dy), 0.01);
          const force = 0.005 / (dist * dist);
          fx += (dx / dist) * force;
          fy += (dy / dist) * force;
        }

        // Attraction to connected rooms
        for (const connId of room.connections) {
          const opos = positions.get(connId);
          if (!opos) continue;
          const dx = opos.x - pos.x;
          const dy = opos.y - pos.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          const force = dist * 0.1;
          fx += (dx / dist) * force;
          fy += (dy / dist) * force;
        }

        // Center gravity
        fx += (0.5 - pos.x) * 0.01;
        fy += (0.5 - pos.y) * 0.01;

        pos.x = Math.max(0.05, Math.min(0.95, pos.x + fx));
        pos.y = Math.max(0.05, Math.min(0.95, pos.y + fy));
      }
    }

    return positions;
  }
}
