import type { GameState, Player, FloorDef } from "../types";

const SAVE_KEY = "etd-save";

/** Create a fresh player for a new game */
export function createNewPlayer(): Player {
  return {
    entityType: "player",
    name: "Adventurer",
    level: 1,
    xp: 0,
    xpToNext: 50,
    stats: {
      hp: 50,
      maxHp: 50,
      mana: 20,
      maxMana: 20,
      attack: 8,
      defense: 4,
      speed: 5,
    },
    inventory: [],
    runes: [],
    spells: [],
    spellSlots: 3,
    equippedSpells: [],
    gold: 0,
  };
}

/** Create a fresh game state */
export function createNewGameState(floors: FloorDef[]): GameState {
  const firstFloor = floors[0];
  return {
    player: createNewPlayer(),
    currentFloor: firstFloor?.id ?? 1,
    currentRoomId: firstFloor?.startRoomId ?? "",
    floors: structuredClone(floors),
    dungeonTick: 0,
    ticksSinceBoss: 0,
    gameOver: false,
    escaped: false,
    seed: Date.now(),
  };
}

// ── Singleton state manager ──

let currentState: GameState | null = null;

export function getState(): GameState {
  if (!currentState) {
    throw new Error("GameState not initialized. Call initState() or loadState() first.");
  }
  return currentState;
}

export function setState(state: GameState): void {
  currentState = state;
}

export function initState(floors: FloorDef[]): GameState {
  currentState = createNewGameState(floors);
  return currentState;
}

/** Advance the dungeon tick. Returns true if a boss should spawn. */
export function advanceTick(): boolean {
  const state = getState();
  state.dungeonTick++;
  state.ticksSinceBoss++;
  if (state.ticksSinceBoss >= 3) {
    state.ticksSinceBoss = 0;
    return true; // boss spawn
  }
  return false;
}

// ── Save / Load ──

export function saveState(): void {
  const state = getState();
  try {
    localStorage.setItem(SAVE_KEY, JSON.stringify(state));
    console.log("Game saved.");
  } catch (e) {
    console.error("Failed to save game:", e);
  }
}

export function loadState(): GameState | null {
  try {
    const raw = localStorage.getItem(SAVE_KEY);
    if (!raw) return null;
    const state: GameState = JSON.parse(raw);
    currentState = state;
    return state;
  } catch (e) {
    console.error("Failed to load save:", e);
    return null;
  }
}

export function hasSave(): boolean {
  return localStorage.getItem(SAVE_KEY) !== null;
}

export function deleteSave(): void {
  localStorage.removeItem(SAVE_KEY);
}
