import type { KAPLAYCtx } from "kaplay";
import { loadBasePack, registry } from "../content";
import { initState } from "../state";

export function registerIntro(k: KAPLAYCtx) {
  k.scene("intro", () => {
    const lines = [
      "You awaken in darkness...",
      "The cold stone beneath you tells you",
      "this is no ordinary place.",
      "",
      "A dungeon of twelve floors",
      "stretches above you.",
      "",
      "Find the runes. Forge your spells.",
      "Fight or negotiate your way out.",
      "",
      "Escape... or perish.",
    ];

    // Fade-in text
    lines.forEach((line, i) => {
      const t = k.add([
        k.text(line, { size: 18 }),
        k.pos(k.width() / 2, 80 + i * 36),
        k.anchor("center"),
        k.color(180, 180, 200),
        k.opacity(0),
      ]);
      // Stagger fade-in
      k.wait(0.3 + i * 0.4, () => {
        k.tween(0, 1, 0.6, (v) => { t.opacity = v; }, k.easings.easeOutCubic);
      });
    });

    // "Click to continue" prompt, appears after all lines
    k.wait(0.3 + lines.length * 0.4 + 0.5, () => {
      const prompt = k.add([
        k.text("[Click anywhere to begin your descent]", { size: 16 }),
        k.pos(k.width() / 2, 550),
        k.anchor("center"),
        k.color(100, 100, 120),
        k.opacity(0),
      ]);
      k.tween(0, 1, 0.8, (v) => { prompt.opacity = v; }, k.easings.easeOutCubic);

      k.onMousePress(async () => {
        // Load content and init game state before entering floor map
        try {
          await loadBasePack();
          const floors = registry.getAllFloors();
          initState(floors);
          k.go("floorMap");
        } catch (err) {
          console.error("Failed to load content pack:", err);
          // Show error on screen
          k.add([
            k.text("Error loading game data!", { size: 20 }),
            k.pos(k.width() / 2, k.height() / 2),
            k.anchor("center"),
            k.color(255, 80, 80),
          ]);
        }
      });
    });
  });
}
