import kaplay from "kaplay";
import { registerMainMenu } from "./scenes/mainMenu";
import { registerIntro } from "./scenes/intro";
import { registerFloorMap } from "./scenes/floorMap";
import { registerCombat } from "./scenes/combat";
import { registerVictory } from "./scenes/victory";
import { registerGameOver } from "./scenes/gameOver";
import { registerForge } from "./scenes/forge";

// Initialize KAPLAY
const k = kaplay({
  width: 800,
  height: 600,
  background: [10, 10, 15],
  global: false,
});

// Register all scenes
registerMainMenu(k);
registerIntro(k);
registerFloorMap(k);
registerCombat(k);
registerVictory(k);
registerGameOver(k);
registerForge(k);

// Start at main menu
k.go("mainMenu");
