import type { KAPLAYCtx } from "kaplay";
import { hasSave, loadState } from "../state";
import { loadBasePack } from "../content";

export function registerMainMenu(k: KAPLAYCtx) {
  k.scene("mainMenu", () => {
    // Title
    k.add([
      k.text("Escape the Dungeon", { size: 48 }),
      k.pos(k.width() / 2, 120),
      k.anchor("center"),
      k.color(200, 180, 100),
    ]);

    // Subtitle
    k.add([
      k.text("A Roguelike Dungeon Crawler", { size: 20 }),
      k.pos(k.width() / 2, 180),
      k.anchor("center"),
      k.color(150, 150, 150),
    ]);

    // Decorative line
    k.add([
      k.rect(300, 2),
      k.pos(k.width() / 2, 210),
      k.anchor("center"),
      k.color(80, 70, 50),
    ]);

    // New Game button
    const newGameBtn = k.add([
      k.rect(220, 50, { radius: 8 }),
      k.pos(k.width() / 2, 300),
      k.anchor("center"),
      k.color(60, 100, 60),
      k.area(),
      "btn",
    ]);

    k.add([
      k.text("New Game", { size: 24 }),
      k.pos(k.width() / 2, 300),
      k.anchor("center"),
      k.color(220, 220, 220),
    ]);

    newGameBtn.onClick(() => {
      k.go("intro");
    });

    // Continue button (dimmed if no save)
    const saveExists = hasSave();
    const continueBtn = k.add([
      k.rect(220, 50, { radius: 8 }),
      k.pos(k.width() / 2, 370),
      k.anchor("center"),
      k.color(saveExists ? 50 : 30, saveExists ? 50 : 30, saveExists ? 80 : 40),
      k.area(),
      "btn",
    ]);

    k.add([
      k.text("Continue", { size: 24 }),
      k.pos(k.width() / 2, 370),
      k.anchor("center"),
      k.color(saveExists ? 180 : 80, saveExists ? 180 : 80, saveExists ? 180 : 80),
    ]);

    if (saveExists) {
      continueBtn.onClick(async () => {
        try {
          await loadBasePack();
          loadState();
          k.go("floorMap");
        } catch (err) {
          console.error("Failed to load save:", err);
        }
      });
    }

    // Version info
    k.add([
      k.text("v0.1.0", { size: 12 }),
      k.pos(k.width() - 10, k.height() - 10),
      k.anchor("botright"),
      k.color(60, 60, 60),
    ]);

    // Hover effects
    k.onHover("btn", (btn) => {
      btn.color = btn.color.lighten(20);
      k.setCursor("pointer");
    });
    k.onHoverEnd("btn", (btn) => {
      btn.color = btn.color.darken(20);
      k.setCursor("default");
    });
  });
}
