import type { KAPLAYCtx } from "kaplay";
import { getState, saveState } from "../state";
import { registry } from "../content";
import type { EnemyDef, GameState, RuneLetter } from "../types";
import { learnRune } from "../spells";

export function registerCombat(k: KAPLAYCtx) {
  k.scene("combat", () => {
    const state = getState();
    const floor = state.floors.find((f) => f.id === state.currentFloor);
    const room = floor?.rooms.find((r) => r.id === state.currentRoomId);

    // Pick an enemy
    let enemy: EnemyDef | undefined;
    if (room?.type === "boss" || state.ticksSinceBoss === 0) {
      // Boss encounter
      enemy = registry.getBossForFloor(state.currentFloor);
    }
    if (!enemy && room?.enemyPool?.length) {
      const enemyId = room.enemyPool[Math.floor(Math.random() * room.enemyPool.length)];
      enemy = registry.getEnemy(enemyId);
    }
    if (!enemy) {
      // Fallback: random floor enemy
      const floorEnemies = registry.getEnemiesForFloor(state.currentFloor).filter((e) => !e.isBoss);
      if (floorEnemies.length > 0) {
        enemy = floorEnemies[Math.floor(Math.random() * floorEnemies.length)];
      }
    }

    if (!enemy) {
      // No enemies available, return to map
      k.go("floorMap");
      return;
    }

    // Clone enemy stats for this combat instance
    const enemyStats = { ...enemy.stats };

    // ── Combat UI ──

    // Background darken
    k.add([
      k.rect(k.width(), k.height()),
      k.pos(0, 0),
      k.color(5, 5, 10),
      k.opacity(0.95),
    ]);

    // Enemy display
    k.add([
      k.text(enemy.name, { size: 28 }),
      k.pos(k.width() / 2, 50),
      k.anchor("center"),
      k.color(enemy.isBoss ? 220 : 180, enemy.isBoss ? 50 : 80, enemy.isBoss ? 50 : 80),
    ]);

    k.add([
      k.text(enemy.description, { size: 14 }),
      k.pos(k.width() / 2, 80),
      k.anchor("center"),
      k.color(140, 140, 150),
    ]);

    // Enemy HP bar
    const enemyHpBg = k.add([
      k.rect(300, 20, { radius: 4 }),
      k.pos(k.width() / 2 - 150, 110),
      k.color(40, 10, 10),
    ]);

    const enemyHpBar = k.add([
      k.rect(300, 20, { radius: 4 }),
      k.pos(k.width() / 2 - 150, 110),
      k.color(180, 40, 40),
    ]);

    const enemyHpText = k.add([
      k.text(`${enemyStats.hp}/${enemyStats.maxHp}`, { size: 12 }),
      k.pos(k.width() / 2, 120),
      k.anchor("center"),
      k.color(220, 220, 220),
    ]);

    // Player stats
    const playerHpBg = k.add([
      k.rect(300, 20, { radius: 4 }),
      k.pos(k.width() / 2 - 150, 440),
      k.color(10, 40, 10),
    ]);

    const playerHpBar = k.add([
      k.rect(300, 20, { radius: 4 }),
      k.pos(k.width() / 2 - 150, 440),
      k.color(40, 160, 40),
    ]);

    const playerHpText = k.add([
      k.text(`HP: ${state.player.stats.hp}/${state.player.stats.maxHp}`, { size: 12 }),
      k.pos(k.width() / 2, 450),
      k.anchor("center"),
      k.color(220, 220, 220),
    ]);

    const playerManaText = k.add([
      k.text(`MP: ${state.player.stats.mana}/${state.player.stats.maxMana}`, { size: 12 }),
      k.pos(k.width() / 2, 475),
      k.anchor("center"),
      k.color(100, 100, 220),
    ]);

    // Combat log
    const logLines: string[] = ["Battle begins!"];
    const logText = k.add([
      k.text("Battle begins!", { size: 13, width: 500 }),
      k.pos(k.width() / 2, 200),
      k.anchor("center"),
      k.color(200, 200, 180),
    ]);

    function addLog(msg: string) {
      logLines.push(msg);
      if (logLines.length > 5) logLines.shift();
      logText.text = logLines.join("\n");
    }

    function updateUI() {
      const hpRatio = Math.max(0, enemyStats.hp / enemyStats.maxHp);
      enemyHpBar.width = 300 * hpRatio;
      enemyHpText.text = `${Math.max(0, enemyStats.hp)}/${enemyStats.maxHp}`;

      const pHpRatio = Math.max(0, state.player.stats.hp / state.player.stats.maxHp);
      playerHpBar.width = 300 * pHpRatio;
      playerHpText.text = `HP: ${state.player.stats.hp}/${state.player.stats.maxHp}`;
      playerManaText.text = `MP: ${state.player.stats.mana}/${state.player.stats.maxMana}`;
    }

    let combatOver = false;

    // ── Action Buttons ──
    const actions = ["Fight", "Spells", "Bag", "Run"];
    actions.forEach((action, i) => {
      const btn = k.add([
        k.rect(150, 40, { radius: 6 }),
        k.pos(120 + i * 160, 530),
        k.anchor("center"),
        k.color(50, 50, 70),
        k.area(),
        "combatBtn",
      ]);
      k.add([
        k.text(action, { size: 18 }),
        k.pos(120 + i * 160, 530),
        k.anchor("center"),
        k.color(200, 200, 200),
      ]);

      btn.onClick(() => {
        if (combatOver) return;
        handleAction(action);
      });
    });

    function handleAction(action: string) {
      switch (action) {
        case "Fight": {
          // Player attacks
          const playerDmg = Math.max(1, state.player.stats.attack - enemyStats.defense + Math.floor(Math.random() * 4));
          enemyStats.hp -= playerDmg;
          addLog(`You deal ${playerDmg} damage!`);

          if (enemyStats.hp <= 0) {
            handleVictory(state, enemy!);
            return;
          }

          // Enemy attacks
          enemyTurn(state, enemyStats);
          break;
        }
        case "Spells": {
          if (state.player.equippedSpells.length === 0) {
            addLog("No spells equipped!");
            return;
          }
          // Show spell selection sub-menu
          showSpellMenu();
          break;
        }
        case "Bag": {
          // Use first consumable HP item
          const potion = state.player.inventory.find(
            (item) => item.type === "consumable" && item.effect?.stat === "hp"
          );
          if (!potion) {
            addLog("No healing items!");
            return;
          }
          const healAmt = potion.effect!.value;
          state.player.stats.hp = Math.min(state.player.stats.maxHp, state.player.stats.hp + healAmt);
          state.player.inventory = state.player.inventory.filter((i) => i !== potion);
          addLog(`Used ${potion.name}! Healed ${healAmt} HP.`);

          enemyTurn(state, enemyStats);
          break;
        }
        case "Run": {
          const escapeChance = state.player.stats.speed / (state.player.stats.speed + enemyStats.speed);
          if (Math.random() < escapeChance) {
            addLog("You escaped!");
            combatOver = true;
            k.wait(1, () => k.go("floorMap"));
          } else {
            addLog("Failed to escape!");
            enemyTurn(state, enemyStats);
          }
          break;
        }
      }
      updateUI();
    }

    // Spell selection sub-menu elements
    const spellMenuItems: ReturnType<typeof k.add>[] = [];

    function showSpellMenu() {
      clearSpellMenu();
      const spells = state.player.equippedSpells;

      // Background panel
      const panel = k.add([
        k.rect(400, 40 + spells.length * 35, { radius: 8 }),
        k.pos(k.width() / 2, 320),
        k.anchor("center"),
        k.color(20, 20, 35),
        k.opacity(0.95),
      ]);
      spellMenuItems.push(panel);

      const title = k.add([
        k.text("Choose Spell:", { size: 14 }),
        k.pos(k.width() / 2, 320 - spells.length * 17 - 5),
        k.anchor("center"),
        k.color(160, 140, 100),
      ]);
      spellMenuItems.push(title);

      spells.forEach((spell, i) => {
        const canCast = state.player.stats.mana >= spell.manaCost;
        const sy = 320 - spells.length * 17 + 20 + i * 35;

        const spellBtn = k.add([
          k.rect(360, 28, { radius: 4 }),
          k.pos(k.width() / 2, sy),
          k.anchor("center"),
          k.color(canCast ? 40 : 25, canCast ? 40 : 25, canCast ? 60 : 35),
          k.area(),
        ]);
        spellMenuItems.push(spellBtn);

        const label = k.add([
          k.text(`${spell.name} (${spell.power} pow, ${spell.manaCost} MP)`, { size: 12 }),
          k.pos(k.width() / 2, sy),
          k.anchor("center"),
          k.color(canCast ? 200 : 100, canCast ? 200 : 100, canCast ? 200 : 100),
        ]);
        spellMenuItems.push(label);

        if (canCast) {
          spellBtn.onClick(() => {
            castSpell(i);
            clearSpellMenu();
          });
        }
      });

      // Cancel button
      const cancelY = 320 + spells.length * 17 + 5;
      const cancelBtn = k.add([
        k.rect(100, 25, { radius: 4 }),
        k.pos(k.width() / 2, cancelY),
        k.anchor("center"),
        k.color(60, 40, 40),
        k.area(),
      ]);
      spellMenuItems.push(cancelBtn);

      const cancelLabel = k.add([
        k.text("Cancel", { size: 12 }),
        k.pos(k.width() / 2, cancelY),
        k.anchor("center"),
        k.color(180, 160, 160),
      ]);
      spellMenuItems.push(cancelLabel);

      cancelBtn.onClick(() => clearSpellMenu());
    }

    function clearSpellMenu() {
      for (const item of spellMenuItems) {
        item.destroy();
      }
      spellMenuItems.length = 0;
    }

    function castSpell(spellIndex: number) {
      const spell = state.player.equippedSpells[spellIndex];
      if (!spell || state.player.stats.mana < spell.manaCost) return;

      state.player.stats.mana -= spell.manaCost;

      if (spell.effect === "heal") {
        const healAmt = spell.power;
        state.player.stats.hp = Math.min(state.player.stats.maxHp, state.player.stats.hp + healAmt);
        addLog(`${spell.name} heals ${healAmt} HP!`);
      } else if (spell.effect === "shield") {
        // Temporary defense buff (simplified: just reduce next enemy damage)
        state.player.stats.defense += Math.floor(spell.power * 0.3);
        addLog(`${spell.name} raises a shield! Defense +${Math.floor(spell.power * 0.3)}`);
      } else if (spell.effect === "buff") {
        state.player.stats.attack += Math.floor(spell.power * 0.2);
        addLog(`${spell.name} empowers you! Attack +${Math.floor(spell.power * 0.2)}`);
      } else if (spell.effect === "debuff") {
        enemyStats.defense = Math.max(0, enemyStats.defense - Math.floor(spell.power * 0.3));
        addLog(`${spell.name} weakens ${enemy!.name}! Def -${Math.floor(spell.power * 0.3)}`);
      } else {
        // damage
        const spellDmg = spell.power + Math.floor(Math.random() * 5);
        enemyStats.hp -= spellDmg;
        addLog(`${spell.name} deals ${spellDmg} damage!`);
      }

      if (enemyStats.hp <= 0) {
        handleVictory(state, enemy!);
        updateUI();
        return;
      }

      enemyTurn(state, enemyStats);
      updateUI();
    }

    function enemyTurn(gs: GameState, es: typeof enemyStats) {
      const eDmg = Math.max(1, es.attack - gs.player.stats.defense + Math.floor(Math.random() * 3));
      gs.player.stats.hp -= eDmg;
      addLog(`${enemy!.name} deals ${eDmg} damage!`);

      if (gs.player.stats.hp <= 0) {
        gs.player.stats.hp = 0;
        handleDefeat();
      }
      updateUI();
    }

    function handleVictory(gs: GameState, e: EnemyDef) {
      combatOver = true;
      addLog(`${e.name} defeated!`);
      gs.player.xp += e.xpReward;
      gs.player.gold += e.goldReward;
      addLog(`+${e.xpReward} XP, +${e.goldReward} gold`);

      // Level up check
      while (gs.player.xp >= gs.player.xpToNext) {
        gs.player.xp -= gs.player.xpToNext;
        gs.player.level++;
        gs.player.xpToNext = Math.floor(gs.player.xpToNext * 1.5);
        gs.player.stats.maxHp += 10;
        gs.player.stats.hp = gs.player.stats.maxHp;
        gs.player.stats.maxMana += 5;
        gs.player.stats.mana = gs.player.stats.maxMana;
        gs.player.stats.attack += 2;
        gs.player.stats.defense += 1;
        addLog(`Level up! Now level ${gs.player.level}`);
      }

      // Loot
      for (const lootEntry of e.loot) {
        if (Math.random() < lootEntry.chance) {
          const item = registry.getItem(lootEntry.itemId);
          if (item) {
            if (item.type === "rune" && item.runeGrant) {
              const learned = learnRune(gs.player.runes, item.runeGrant as RuneLetter);
              if (learned) {
                addLog(`Learned rune: ${item.runeGrant}!`);
              } else {
                addLog(`Already know rune ${item.runeGrant}.`);
              }
            } else {
              gs.player.inventory.push({ ...item });
              addLog(`Found: ${item.name}`);
            }
          }
        }
      }

      saveState();
      updateUI();
      k.wait(2, () => k.go("floorMap"));
    }

    function handleDefeat() {
      combatOver = true;
      addLog("You have fallen...");
      state.gameOver = true;
      saveState();
      updateUI();
      k.wait(2, () => k.go("gameOver"));
    }
  });
}
