import type { KAPLAYCtx } from "kaplay";
import { getState, saveState } from "../state";
import { registry } from "../content";
import { composeSpell } from "../spells";
import type { RuneLetter } from "../types";

export function registerForge(k: KAPLAYCtx) {
  k.scene("forge", () => {
    const state = getState();
    const selectedRunes: RuneLetter[] = [];

    // Background
    k.add([
      k.rect(k.width(), k.height()),
      k.pos(0, 0),
      k.color(15, 12, 8),
    ]);

    // Title
    k.add([
      k.text("Runic Forge", { size: 32 }),
      k.pos(k.width() / 2, 30),
      k.anchor("center"),
      k.color(200, 150, 50),
    ]);

    k.add([
      k.text("Select runes to compose a spell (2+ runes required)", { size: 14 }),
      k.pos(k.width() / 2, 65),
      k.anchor("center"),
      k.color(140, 130, 100),
    ]);

    // Available runes display
    k.add([
      k.text("Your Runes:", { size: 16 }),
      k.pos(40, 100),
      k.color(180, 160, 100),
    ]);

    const runeButtons: Array<{ letter: RuneLetter; selected: boolean }> = [];

    if (state.player.runes.length === 0) {
      k.add([
        k.text("No runes discovered yet.", { size: 14 }),
        k.pos(40, 130),
        k.color(100, 100, 100),
      ]);
    } else {
      state.player.runes.forEach((letter, i) => {
        const rune = registry.getRune(letter);
        if (!rune) return;

        const col = i % 6;
        const row = Math.floor(i / 6);
        const bx = 70 + col * 120;
        const by = 135 + row * 70;

        const runeData = { letter, selected: false };
        runeButtons.push(runeData);

        const btn = k.add([
          k.rect(100, 55, { radius: 6 }),
          k.pos(bx, by),
          k.anchor("center"),
          k.color(40, 35, 25),
          k.area(),
          "runeBtn",
        ]);

        k.add([
          k.text(`${rune.letter} - ${rune.name}`, { size: 13 }),
          k.pos(bx, by - 8),
          k.anchor("center"),
          k.color(200, 180, 100),
        ]);

        k.add([
          k.text(`${rune.affinity} +${rune.power}`, { size: 10 }),
          k.pos(bx, by + 10),
          k.anchor("center"),
          k.color(140, 140, 140),
        ]);

        btn.onClick(() => {
          if (runeData.selected) {
            // Deselect
            runeData.selected = false;
            btn.color = k.rgb(40, 35, 25);
            const idx = selectedRunes.indexOf(letter);
            if (idx >= 0) selectedRunes.splice(idx, 1);
          } else {
            // Select
            runeData.selected = true;
            btn.color = k.rgb(80, 70, 30);
            selectedRunes.push(letter);
          }
          updatePreview();
        });
      });
    }

    // Spell preview area
    k.add([
      k.rect(350, 120, { radius: 8 }),
      k.pos(k.width() / 2, 380),
      k.anchor("center"),
      k.color(25, 22, 18),
      k.opacity(0.9),
    ]);

    k.add([
      k.text("Spell Preview", { size: 16 }),
      k.pos(k.width() / 2, 335),
      k.anchor("center"),
      k.color(160, 140, 80),
    ]);

    const previewText = k.add([
      k.text("Select 2+ runes to preview a spell", { size: 13, width: 320 }),
      k.pos(k.width() / 2, 385),
      k.anchor("center"),
      k.color(140, 140, 140),
    ]);

    function updatePreview() {
      if (selectedRunes.length < 2) {
        previewText.text = `Selected: ${selectedRunes.length} rune(s). Need 2+ to compose.`;
        previewText.color = k.rgb(140, 140, 140);
        return;
      }
      const spell = composeSpell(selectedRunes);
      if (spell) {
        previewText.text = `${spell.name}\n${spell.effect} (${spell.affinity})\nPower: ${spell.power}  Cost: ${spell.manaCost} MP`;
        previewText.color = k.rgb(200, 180, 100);
      } else {
        previewText.text = "Cannot compose spell from these runes.";
        previewText.color = k.rgb(180, 80, 80);
      }
    }

    // Compose button
    const composeBtn = k.add([
      k.rect(180, 45, { radius: 6 }),
      k.pos(k.width() / 2 - 100, 470),
      k.anchor("center"),
      k.color(60, 90, 60),
      k.area(),
    ]);

    k.add([
      k.text("Forge Spell", { size: 18 }),
      k.pos(k.width() / 2 - 100, 470),
      k.anchor("center"),
      k.color(200, 200, 200),
    ]);

    composeBtn.onClick(() => {
      if (selectedRunes.length < 2) return;
      if (state.player.spells.length >= state.player.spellSlots) {
        previewText.text = "Spell slots full! Max " + state.player.spellSlots + " spells.";
        previewText.color = k.rgb(180, 80, 80);
        return;
      }

      const spell = composeSpell(selectedRunes);
      if (spell) {
        state.player.spells.push(spell);
        state.player.equippedSpells.push(spell);
        saveState();
        previewText.text = `Forged: ${spell.name}! (${state.player.spells.length}/${state.player.spellSlots} slots)`;
        previewText.color = k.rgb(100, 200, 100);
        // Clear selection
        selectedRunes.length = 0;
        for (const rd of runeButtons) rd.selected = false;
      }
    });

    // Back button
    const backBtn = k.add([
      k.rect(180, 45, { radius: 6 }),
      k.pos(k.width() / 2 + 100, 470),
      k.anchor("center"),
      k.color(70, 50, 50),
      k.area(),
    ]);

    k.add([
      k.text("Leave Forge", { size: 18 }),
      k.pos(k.width() / 2 + 100, 470),
      k.anchor("center"),
      k.color(200, 200, 200),
    ]);

    backBtn.onClick(() => {
      k.go("floorMap");
    });

    // Current spells display
    k.add([
      k.text(`Spells: ${state.player.spells.length}/${state.player.spellSlots}`, { size: 13 }),
      k.pos(k.width() - 20, 100),
      k.anchor("topright"),
      k.color(120, 120, 160),
    ]);

    state.player.spells.forEach((spell, i) => {
      k.add([
        k.text(`${spell.name} (${spell.affinity}, ${spell.power} pow)`, { size: 11 }),
        k.pos(k.width() - 20, 125 + i * 20),
        k.anchor("topright"),
        k.color(100, 100, 140),
      ]);
    });
  });
}
